"""Tests for configuration system (Unit 1)."""
import json
import os
import tempfile
from pathlib import Path

import pytest

from codeagent.config.settings import (
    CodeAgentConfig,
    load_config,
    _deep_merge,
    _load_json_file,
)
from codeagent.config.schema import ModelConfig, PermissionsConfig


class TestDeepMerge:
    def test_simple_merge(self):
        base = {"a": 1, "b": 2}
        override = {"b": 3, "c": 4}
        result = _deep_merge(base, override)
        assert result == {"a": 1, "b": 3, "c": 4}

    def test_nested_merge(self):
        base = {"model": {"provider": "openai", "model_name": "gpt-4o"}}
        override = {"model": {"model_name": "gpt-4o-mini"}}
        result = _deep_merge(base, override)
        assert result["model"]["provider"] == "openai"
        assert result["model"]["model_name"] == "gpt-4o-mini"

    def test_override_wins(self):
        base = {"x": [1, 2]}
        override = {"x": [3]}
        result = _deep_merge(base, override)
        assert result["x"] == [3]


class TestLoadJsonFile:
    def test_valid_json(self, tmp_path):
        f = tmp_path / "test.json"
        f.write_text('{"model": {"provider": "anthropic"}}')
        data = _load_json_file(f)
        assert data["model"]["provider"] == "anthropic"

    def test_invalid_json(self, tmp_path):
        f = tmp_path / "bad.json"
        f.write_text("{invalid json")
        data = _load_json_file(f)
        assert data == {}

    def test_nonexistent_file(self, tmp_path):
        data = _load_json_file(tmp_path / "nope.json")
        assert data == {}


class TestCodeAgentConfig:
    def test_defaults(self):
        config = CodeAgentConfig()
        assert config.model.provider == "openai"
        assert config.model.model_name == "gpt-4o"
        assert config.permissions.mode == "default"
        assert config.model.stream is True

    def test_custom_model(self):
        config = CodeAgentConfig(
            model=ModelConfig(provider="anthropic", model_name="claude-sonnet-4-20250514"),
        )
        assert config.model.provider == "anthropic"
        assert config.model.model_name == "claude-sonnet-4-20250514"

    def test_permissions_config(self):
        config = CodeAgentConfig(
            permissions=PermissionsConfig(mode="bypassPermissions"),
        )
        assert config.permissions.mode == "bypassPermissions"


class TestLoadConfig:
    def test_load_defaults(self):
        """Loading config without any config files should return defaults."""
        config = load_config()
        assert isinstance(config, CodeAgentConfig)
        assert config.model.provider == "openai"

    def test_env_override(self, monkeypatch):
        """Environment variables should override defaults."""
        monkeypatch.setenv("CODEAGENT_MODEL", "gpt-4o-mini")
        monkeypatch.setenv("CODEAGENT_PROVIDER", "openai")
        config = load_config()
        assert config.model.model_name == "gpt-4o-mini"

